#!/usr/bin/env node
/**
 * Generate the active brand version for runtime use.
 */

import { writeFileSync } from "node:fs";
import { dirname, resolve } from "node:path";
import { fileURLToPath } from "node:url";
import { readActiveBrandMetadata } from "./brand-metadata.mjs";

const root = resolve(dirname(fileURLToPath(import.meta.url)), "..");
const brand = readActiveBrandMetadata(root);
const outputPath = resolve(root, "pi/coding-agent/src/brand-version.generated.ts");
const content = `/**
 * Generated brand version - DO NOT EDIT
 * Generated by scripts/generate-brand-version.mjs
 * Active brand: ${brand.activeBrand}
 */

export const BRAND_VERSION = "${brand.version}";
export const BRAND_NAME = "${brand.displayName}";
`;

writeFileSync(outputPath, content);
console.log(`Generated brand version: ${brand.displayName} v${brand.version}`);
